const CHIP_COSTS={COMMON:{GOLD:10,DIAMOND:25,RAINBOW:40,BESKAR:80},RARE:{GOLD:30,DIAMOND:60,RAINBOW:100,BESKAR:250},EPIC:{GOLD:120,DIAMOND:180,RAINBOW:240,BESKAR:5000},LEGENDARY:{GOLD:400,DIAMOND:1200,RAINBOW:4000,BESKAR:12000},MYTHIC:{GOLD:8000,DIAMOND:15000,RAINBOW:40000,BESKAR:80000}};
