function toggleFlawless(name,variant){const d=state.droids.find(x=>x.name===name);if(isIconic(d)||!droidexEntry(name,variant))return;const flawless=!isDroidFlawless(name);state.droidex.filter(x=>x.name===name).forEach(x=>x.flawless=flawless);save()}
function addDetailDroidexControls(){if(!location.hash.startsWith('#/droid/')||document.querySelector('.detail-actions'))return;const add=document.querySelector('#addThis');if(!add)return;const d=state.droids.find(x=>slug(x.name)===location.hash.split('/')[2]);const active=document.querySelector('.variant-tabs button.active');if(!d)return;const variant=isIconic(d)?'DEFAULT':active?.dataset.v||'DEFAULT',entry=droidexEntry(d.name,variant),flawless=isDroidFlawless(d.name);add.insertAdjacentHTML('afterend',`<div class="detail-actions"><button class="btn secondary" id="toggleDex">${entry?'Remove from':'Add to'} Droidex</button>${isIconic(d)?'':`<button class="flawless-toggle ${flawless?'active':''}" id="toggleFlawless" ${entry?'':'disabled'}>✦ ${flawless?'Flawless':'Mark flawless'}</button>`}</div>`);document.querySelector('#toggleDex').onclick=()=>{toggleDroidex(d.name,variant);toast(entry?'Removed from Droidex':'Added to Droidex');document.querySelector('.detail-actions').remove();addDetailDroidexControls()};const flawlessButton=document.querySelector('#toggleFlawless');if(flawlessButton)flawlessButton.onclick=()=>{toggleFlawless(d.name,variant);document.querySelector('.detail-actions').remove();addDetailDroidexControls()}}
function droidexPage(){let variant='DEFAULT';const render=()=>{const collected=state.droidex.filter(x=>x.variant===variant).length,flawless=flawlessCount();app.innerHTML=`<div class="breadcrumbs"><a href="#/">Homepage</a> / Droidex</div><section class="dex-hero"><div><p class="eyebrow">Collection tracker</p><h1>Droidex</h1><p>Collect every droid quality and mark your flawless finds.</p></div><div class="dex-totals"><strong>${state.droidex.length}/${state.droids.length*VARIANTS.length}</strong><span>✦ ${flawless}/${flawlessCapacity()} flawless · +${(flawless*.01).toFixed(2)}× credits</span><button class="btn secondary" id="transferDroidex">⇄ Import / Export</button></div></section><div class="variant-tabs dex-tabs">${VARIANTS.map(v=>`<button data-dex-variant="${v}" class="${v===variant?'active':''}">${v[0]+v.slice(1).toLowerCase()}</button>`).join('')}</div><div class="dex-toolbar"><input id="dexSearch" class="form-control" placeholder="Search Droidex…"><label><input id="dexMissing" type="checkbox"> Missing only</label><span>${collected}/${state.droids.length} ${variant.toLowerCase()} collected</span></div><div id="dexGrid" class="dex-grid"></div>`;const draw=()=>{const q=document.querySelector('#dexSearch').value.toLowerCase(),missing=document.querySelector('#dexMissing').checked;const list=state.droids.filter(d=>d.name.toLowerCase().includes(q)&&(!missing||!droidexEntry(d.name,variant)));document.querySelector('#dexGrid').innerHTML=list.map(d=>{const entry=droidexEntry(d.name,variant),flawless=isDroidFlawless(d.name);return `<article class="dex-card ${entry?'collected':'missing'} ${flawless?'flawless':''}"><a href="#/droid/${slug(d.name)}">${picture(d,variant)}<span class="badge">${d.rarity}</span><strong>${d.name}</strong></a><div><button class="dex-own" data-dex-own="${d.name}">${entry?'✓ Owned':'+ Add'}</button><button class="dex-flawless" data-dex-flawless="${d.name}" ${entry?'':'disabled'}>✦ ${flawless?'Flawless':'Flawless?'}</button></div></article>`}).join('');document.querySelectorAll('[data-dex-own]').forEach(b=>b.onclick=()=>{toggleDroidex(b.dataset.dexOwn,variant);render()});document.querySelectorAll('[data-dex-flawless]').forEach(b=>b.onclick=()=>{toggleFlawless(b.dataset.dexFlawless,variant);render()})};document.querySelectorAll('[data-dex-variant]').forEach(b=>b.onclick=()=>{variant=b.dataset.dexVariant;render()});document.querySelector('#transferDroidex').onclick=()=>showDroidexTransferModal(render);document.querySelector('#dexSearch').oninput=draw;document.querySelector('#dexMissing').onchange=draw;draw()};render()}
function home(){const featured=[...state.droids].sort(()=>Math.random()-.5).slice(0,4);app.innerHTML=`<section class="hero"><p class="eyebrow">Community knowledgebase</p><h1>Droid Tycoon, decoded.</h1><p class="lead">Browse every droid and variant, compare production, then build your collection and see exactly which droids to keep for later rebirths.</p></section><div class="quick-grid"><a class="quick-card" href="#/droids"><b>Explore all ${state.droids.length} droids →</b><p>Costs, income, rarity, type, attributes and every quality.</p></a><a class="quick-card" href="#/base"><b>Build your base →</b><p>Add owned droids and calculate live, minute and hourly credits.</p></a></div><h2>Featured droids</h2><div class="droid-grid">${featured.map(card).join('')}</div><h2>About this archive</h2><p class="lead">This is an unofficial companion for the Fortnite island <strong>Droid Tycoon</strong>. Your base is saved only in this browser. The visual language takes cues from classic game wikis: compact facts, readable tables and information-first pages.</p>`}
function droidsPage(){const q=new URLSearchParams(location.hash.split('?')[1]||'');app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / Droids</div><p class="eyebrow">Droidex</p><h1>All droids</h1><p class="lead">The complete archive. Select a droid for its dedicated page and all five quality variants.</p><div class="toolbar"><input id="droidSearch" placeholder="Filter by name…"><select id="typeFilter"><option value="">All types</option>${['WORKER','ASTROMECH','BATTLE'].map(x=>`<option ${q.get('type')===x?'selected':''}>${x}</option>`).join('')}</select><select id="rarityFilter"><option value="">All rarities</option>${['COMMON','RARE','EPIC','LEGENDARY','MYTHIC','ICONIC'].map(x=>`<option>${x}</option>`).join('')}</select></div><p id="resultCount" class="eyebrow"></p><div id="droidGrid" class="droid-grid"></div>`;const draw=()=>{let name=document.querySelector('#droidSearch').value.toLowerCase(),type=document.querySelector('#typeFilter').value,rarity=document.querySelector('#rarityFilter').value;let list=state.droids.filter(d=>d.name.toLowerCase().includes(name)&&(!type||d.type===type)&&(!rarity||d.rarity===rarity));document.querySelector('#resultCount').textContent=`${list.length} entries`;document.querySelector('#droidGrid').innerHTML=list.map(card).join('')};['droidSearch','typeFilter','rarityFilter'].forEach(id=>document.querySelector('#'+id).addEventListener('input',draw));draw()}
function detailPage(id){const d=state.droids.find(x=>slug(x.name)===id);if(!d){notFound();return}let variant='DEFAULT';const render=()=>{const v=d.variants[variant];app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / <a href="#/droids">Droids</a> / ${d.name}</div><div class="article-grid"><article><p class="eyebrow">${d.rarity} ${d.type} droid</p><h1>${d.name}</h1><p class="lead"><strong>${d.name}</strong> is a ${d.rarity.toLowerCase()} ${d.type.toLowerCase()} droid. Its base form produces ${fmt(d.variants.DEFAULT.income)} credits per second and every quality is catalogued below.</p><div class="variant-tabs">${VARIANTS.map(x=>`<button data-v="${x}" class="${variant===x?'active':''}">${x[0]+x.slice(1).toLowerCase()}</button>`).join('')}</div><h2>${variant[0]+variant.slice(1).toLowerCase()} statistics</h2><table><thead><tr><th>Variant</th><th>Crafting cost</th><th>Credits / second</th><th>Credits / hour</th></tr></thead><tbody><tr class="selected-variant"><td><strong>${variant[0]+variant.slice(1).toLowerCase()}</strong></td><td>${fmt(v.cost)}</td><td>${fmt(v.income)}</td><td>${fmt(v.income*3600)}</td></tr></tbody></table><h2>Gameplay</h2><p class="lead">As a ${d.type.toLowerCase()} droid, ${d.name} provides <strong>${ATTRIBUTE[d.type]}</strong>. Production shown in the table is before your in-game credit multiplier.</p><button class="btn" id="addThis">Add ${variant.toLowerCase()} to my base</button></article><aside class="infobox"><div class="info-title">${d.name}</div><div class="info-image">${picture(d,variant)}</div><div class="info-rows"><div class="info-row"><b>Quality</b><span>${variant}</span></div><div class="info-row"><b>Rarity</b><span>${d.rarity}</span></div><div class="info-row"><b>Type</b><span>${d.type}</span></div><div class="info-row"><b>Attribute</b><span>${ATTRIBUTE[d.type]}</span></div><div class="info-row"><b>Cost</b><span>${fmt(v.cost)} credits</span></div><div class="info-row"><b>Income</b><span>${fmt(v.income)}/s</span></div></div></aside></div>`;document.querySelectorAll('[data-v]').forEach(b=>b.onclick=()=>{variant=b.dataset.v;render()});document.querySelector('#addThis').onclick=()=>requestAdd(d.name,variant)};render()}
function commitOwned(name,variant,qty=1,preferred){let row=state.owned.find(x=>x.name===name&&x.variant===variant&&x.preferred===preferred);row?row.qty+=qty:state.owned.push({name,variant,qty,...(preferred?{preferred}:{})});save();toast(`${name} added to your base`)}
function requestAdd(name,variant,qty=1,onDone){const d=state.droids.find(x=>x.name===name),p=placements();const available=capacity(d.type)-p.placed.filter(x=>x.station===d.type).length+capacity('BUILD')-p.placed.filter(x=>x.station==='BUILD').length;if(available>=qty){commitOwned(name,variant,qty);onDone?.();return}showCapacityModal({name,variant,qty,onDone})}
function showCapacityModal(pending){const root=document.querySelector('#modalRoot');const candidates=expandedOwned();root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Base capacity reached</p><h2>No compatible slots are free</h2><p><strong>${pending.name}</strong> needs a matching type slot or one of the universal Build slots.</p><div class="modal-actions"><button class="btn" id="chooseSwap">Swap a droid</button><button class="btn secondary" id="forceAdd">Force add</button><button class="btn ghost" id="cancelAdd">Cancel</button></div><div id="swapChooser"></div></section></div>`;root.querySelector('#cancelAdd').onclick=()=>root.innerHTML='';root.querySelector('#forceAdd').onclick=()=>{commitOwned(pending.name,pending.variant,pending.qty);root.innerHTML='';pending.onDone?.()};root.querySelector('#chooseSwap').onclick=()=>{root.querySelector('#swapChooser').innerHTML=`<label class="field swap-field">Choose the droid to replace<select id="swapTarget" class="form-control">${candidates.map((x,i)=>`<option value="${x.source}">${x.name} · ${x.variant}</option>`).join('')}</select></label><button class="btn" id="confirmSwap">Confirm swap</button>`;root.querySelector('#confirmSwap').onclick=()=>{const index=Number(root.querySelector('#swapTarget').value),row=state.owned[index];row.qty>1?row.qty--:state.owned.splice(index,1);commitOwned(pending.name,pending.variant,pending.qty);root.innerHTML='';pending.onDone?.()}}}
function basePage(){
  const cycles=Object.keys(state.rebirths);
  const slotCard=(type,index,p)=>{const occupant=p.placed.find(x=>x.station===type&&x.slot===index);if(occupant){const d=state.droids.find(x=>x.name===occupant.name);return `<a class="base-slot occupied" href="#/droid/${slug(d.name)}"><div>${picture(d,occupant.variant)}</div><strong>${d.name}</strong><small>${occupant.variant} · ${fmt(d.variants[occupant.variant].income*state.multiplier)}/s</small></a>`}const rule=SLOT_RULES[type],unlock=rule.unlocks[index-rule.initial],isLocked=unlock>state.rebirth;return `<div class="base-slot ${isLocked?'locked':'open'}"><span class="slot-icon">${type==='BUILD'?'⚒':`<img src="${TYPE_IMAGES[type]}" alt="">`}</span><small>${isLocked?`Unlocks at Rebirth ${unlock}`:`${type[0]+type.slice(1).toLowerCase()} slot`}</small></div>`};
  const station=(type,p)=>{const total=SLOT_RULES[type].initial+SLOT_RULES[type].unlocks.length;const active=capacity(type);const used=p.placed.filter(x=>x.station===type).length;return `<section class="station station-${type.toLowerCase()}"><header><span>${type==='BUILD'?'⚒':`<img src="${TYPE_IMAGES[type]}" alt="">`}<strong>${type[0]+type.slice(1).toLowerCase()}</strong></span><small>${used}/${active} slots${total-active?` · ${total-active} future`:''}</small></header><div class="slot-grid">${Array.from({length:total},(_,i)=>slotCard(type,i,p)).join('')}</div></section>`};
  const render=()=>{const p=placements();const income=state.owned.reduce((sum,x)=>{const d=state.droids.find(y=>y.name===x.name);return sum+(d?.variants[x.variant]?.income||0)*x.qty},0)*state.multiplier;const future=(state.rebirths[state.cycle]||[]).filter(r=>r.to>state.rebirth).flatMap(r=>r.requiredDroids.map(req=>({...req,at:r.to})));const futureRows=future.map(req=>{const have=state.owned.some(x=>x.name===req.droidName&&x.variant===req.variant&&x.qty>0);return `<div class="future-item ${have?'have':'missing'}"><b>Rebirth ${req.at}</b><span>${req.variant} <a href="#/droid/${slug(req.droidName)}">${req.droidName}</a></span><span>${have?'✓ In base':'Needed'}</span></div>`}).join('');const roster=state.owned.map((x,i)=>{const d=state.droids.find(y=>y.name===x.name);return `<div class="roster-row"><a href="#/droid/${slug(d.name)}">${picture(d,x.variant)}<span><strong>${d.name}</strong><small>${x.variant} · ×${x.qty}</small></span></a><button class="icon-btn remove" data-i="${i}" title="Remove">×</button></div>`}).join('');
    app.innerHTML=`<div class="breadcrumbs"><a href="#/">Main page</a> / My base</div><div class="base-heading"><div><p class="eyebrow">Personal planner</p><h1>My base</h1></div><button class="btn" id="openAdd">+ Add droid</button></div><div class="base-top"><div class="stat"><small>Credits / second</small><strong>${fmt(income)}</strong></div><div class="stat"><small>Credits / minute</small><strong>${fmt(income*60)}</strong></div><div class="stat"><small>Credits / hour</small><strong>${fmt(income*3600)}</strong></div><div class="stat"><small>Droids owned</small><strong>${state.owned.reduce((s,x)=>s+x.qty,0)}</strong></div></div><section class="panel base-controls"><label class="field">Credit multiplier<input class="form-control" id="multiplier" type="number" min="0" step="0.1" value="${state.multiplier}"></label><label class="field">Super rebirth cycle<select class="form-control" id="cycle">${cycles.map(c=>`<option value="${c}" ${Number(c)===state.cycle?'selected':''}>Cycle ${Number(c)+1}</option>`).join('')}</select></label><label class="field">Current rebirth<select class="form-control" id="rebirth">${Array.from({length:28},(_,n)=>`<option ${n===state.rebirth?'selected':''}>${n}</option>`).join('')}</select></label></section><div class="base-workspace"><div class="station-board">${['WORKER','ASTROMECH','BATTLE','BUILD'].map(t=>station(t,p)).join('')}</div><aside class="roster"><header><strong>Roster</strong><span>${state.owned.reduce((s,x)=>s+x.qty,0)}</span></header>${p.overflow.length?`<div class="overflow-warning">${p.overflow.length} force-added droid${p.overflow.length>1?'s are':' is'} over capacity.</div>`:''}<div>${roster||'<p class="roster-empty">No droids yet. Add one to fill a station.</p>'}</div></aside></div><h2>Needed later in this cycle</h2><div class="notice">Green entries are already in your roster. Requirements begin after your selected current rebirth.</div><div class="future-list">${futureRows||'<div class="empty">Nothing else is required in this cycle.</div>'}</div>`;
    document.querySelector('#multiplier').onchange=e=>{state.multiplier=Number(e.target.value)||0;save();render()};document.querySelector('#cycle').onchange=e=>{state.cycle=Number(e.target.value);save();render()};document.querySelector('#rebirth').onchange=e=>{state.rebirth=Number(e.target.value);save();render()};document.querySelector('#openAdd').onclick=()=>showAddModal(render);document.querySelectorAll('.remove').forEach(b=>b.onclick=()=>{state.owned.splice(Number(b.dataset.i),1);save();render()})};render()}
function showAddModal(onDone){const root=document.querySelector('#modalRoot');root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Roster</p><h2>Add a droid</h2><div class="modal-form"><label class="field">Droid<select id="addName" class="form-control">${state.droids.map(d=>`<option>${d.name}</option>`).join('')}</select></label><label class="field">Variant<select id="addVariant" class="form-control">${VARIANTS.map(v=>`<option>${v}</option>`).join('')}</select></label><label class="field">Quantity<input id="addQty" class="form-control" type="number" min="1" value="1"></label></div><div class="modal-actions"><button class="btn" id="confirmAdd">Add to base</button><button class="btn ghost" id="cancelAdd">Cancel</button></div></section></div>`;root.querySelector('#cancelAdd').onclick=()=>root.innerHTML='';root.querySelector('#confirmAdd').onclick=()=>{const data={name:root.querySelector('#addName').value,variant:root.querySelector('#addVariant').value,qty:Math.max(1,Number(root.querySelector('#addQty').value)||1)};root.innerHTML='';requestAdd(data.name,data.variant,data.qty,onDone)}}
function futureRequirements(){return(state.rebirths[state.cycle]||[]).filter(r=>r.to>state.rebirth).flatMap(r=>r.requiredDroids.map(req=>({...req,at:r.to})))}
function requirementState(name){const req=futureRequirements().find(x=>x.droidName===name);if(!req)return null;const owned=state.owned.filter(x=>x.name===name);const enough=owned.some(x=>VARIANTS.indexOf(x.variant)>=VARIANTS.indexOf(req.variant));return{...req,enough}}
function removeOwnedUnit(index){const row=state.owned[index];if(!row)return;row.qty>1?row.qty--:state.owned.splice(index,1);save()}
function changeOwnedUnitVariant(source,variant,station,slot){const row=state.owned[source];if(!row||row.variant===variant)return;if(row.qty>1){const changed={...row,variant,qty:1,preferred:station,preferredSlot:slot};row.qty--;if(row.preferred===station&&Number(row.preferredSlot)===slot){delete row.preferred;delete row.preferredSlot}state.owned.push(changed)}else{row.variant=variant;row.preferred=station;row.preferredSlot=slot}save()}
function showCardVariantModal(card,onDone){const root=document.querySelector('#modalRoot'),d=state.droids.find(x=>x.name===card.name);if(!d||isIconic(d))return;root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true"><p class="eyebrow">Change quality</p><h2>${d.name}</h2><p class="picker-hint">Choose any quality. You can upgrade or downgrade this exact card without removing it from its slot.</p><div class="variant-choice">${VARIANTS.map(v=>`<button data-card-variant="${v}" ${v===card.variant?'disabled':''}>${picture(d,v)}<strong>${variantLabel(v)}</strong><small>${v===card.variant?'Current quality':`${fmt(d.variants[v].income)}/s`}</small></button>`).join('')}</div><button class="btn ghost" id="cancelVariantChange">Cancel</button></section></div>`;root.querySelectorAll('[data-card-variant]').forEach(button=>button.onclick=()=>{changeOwnedUnitVariant(card.source,button.dataset.cardVariant,card.station,card.slot);root.innerHTML='';onDone()});root.querySelector('#cancelVariantChange').onclick=()=>root.innerHTML=''}
function showSwapModal(card,onDone){const root=document.querySelector('#modalRoot'),p=placements(),source=p.placed.find(x=>x.source===card.source&&x.unit===card.unit),items=p.placed.filter(x=>!(x.source===card.source&&x.unit===card.unit));if(!source)return;root.innerHTML=`<div class="modal-backdrop"><section class="modal slot-picker" role="dialog" aria-modal="true"><p class="eyebrow">Manual swap</p><h2>Swap ${source.name}</h2><p class="picker-hint">Choose another placed droid to swap with. Useful when drag-and-drop is awkward across the page.</p><input id="swapSearch" class="form-control picker-search" placeholder="Search placed droids…" autofocus><div id="swapResults" class="picker-results"></div><button class="btn ghost" id="cancelSwap">Cancel</button></section></div>`;const draw=()=>{const q=root.querySelector('#swapSearch').value.toLowerCase();root.querySelector('#swapResults').innerHTML=items.filter(x=>x.name.toLowerCase().includes(q)||x.station.toLowerCase().includes(q)).map(x=>{const d=state.droids.find(y=>y.name===x.name);return `<button class="picker-droid" data-swap-key="${x.source}:${x.unit}"><span>${picture(d,x.variant)}</span><b>${x.name}</b><small>${variantLabel(x.variant)} · ${x.station}</small></button>`}).join('')||'<p class="roster-empty">No matching placed droids.</p>';root.querySelectorAll('[data-swap-key]').forEach(b=>b.onclick=()=>{moveUnitByKey(`${source.source}:${source.unit}`,b.dataset.swapKey,onDone);root.innerHTML=''})};root.querySelector('#swapSearch').oninput=draw;root.querySelector('#cancelSwap').onclick=()=>root.innerHTML='';draw()}
function showSuperRebirthConfirm(rerender,really=false){const root=document.querySelector('#modalRoot'),question=really?'Are you really sure you want to super rebirth?':'Are you sure you want to super rebirth?';root.innerHTML=`<div class="modal-backdrop"><section class="modal" role="dialog" aria-modal="true" aria-labelledby="superRebirthTitle"><p class="eyebrow">Destructive action</p><h2 id="superRebirthTitle">${question}</h2><p>This will remove every droid from your base and reset its progression. This cannot be undone unless you exported your base first.</p><div class="modal-actions"><button class="btn danger" id="confirmSuperRebirth">Yes, super rebirth</button><button class="btn ghost" id="cancelSuperRebirth">Cancel</button></div></section></div>`;root.querySelector('#cancelSuperRebirth').onclick=()=>root.innerHTML='';root.querySelector('#confirmSuperRebirth').onclick=()=>{if(!really){showSuperRebirthConfirm(rerender,true);return}state.owned=[];state.multiplier=1;state.rebirth=0;state.loungePurchased=0;state.novaLevel=0;const cycleCount=Object.keys(state.rebirths).length;state.cycle=cycleCount?(state.cycle+1)%cycleCount:0;save();root.innerHTML='';toast(`Super rebirth complete · Cycle ${state.cycle+1}`);rerender()}}
function cloudDocFromCurrent(name='Main'){const id=cloudId();return{app:'Droid Archives',version:1,updatedAt:new Date().toISOString(),activeProfileId:id,ui:{theme:state.theme},profiles:[{id,name,updatedAt:new Date().toISOString(),data:profileDataFromState()}]}}
function normalizeCloudDoc(doc){doc=normalizeProfileDoc(doc);doc.ui=doc.ui||{};return doc}
async function waitForGoogle(){for(let i=0;i<40;i++){if(window.google?.accounts?.oauth2)return;if(i===0&&!document.querySelector('script[src*="accounts.google.com/gsi/client"]')){const s=document.createElement('script');s.src='https://accounts.google.com/gsi/client';s.async=true;s.defer=true;document.head.appendChild(s)}await new Promise(r=>setTimeout(r,125))}throw Error('Google sign-in did not load.')}
async function cloudAuth(promptMode){await waitForGoogle();return new Promise((resolve,reject)=>{state.cloud.tokenClient ||= google.accounts.oauth2.initTokenClient({client_id:GOOGLE_CLIENT_ID,scope:DRIVE_SCOPE,callback:res=>{if(res.error){reject(Error(res.error));return}state.cloud.token=res.access_token;state.cloud.enabled=true;state.cloud.status='Google connected';resolve(res.access_token)}});state.cloud.tokenClient.requestAccessToken({prompt:promptMode??(state.cloud.token?'':'consent')})})}
async function driveFetch(path,options={}){const response=await fetch(`https://www.googleapis.com/drive/v3/${path}`,{...options,headers:{Authorization:`Bearer ${state.cloud.token}`,...(options.headers||{})}});if(!response.ok){if(response.status===401||response.status===403)markCloudSignedOut('SIGNED OUT — reconnect Google');throw Error(`Google Drive sync failed (${response.status})`)}return response}
async function findCloudFile(){const q=encodeURIComponent(`name='${CLOUD_FILE_NAME}' and 'appDataFolder' in parents and trashed=false`),response=await driveFetch(`files?spaces=appDataFolder&fields=files(id,name,modifiedTime)&q=${q}`),data=await response.json();return data.files?.[0]||null}
function multipartBody(metadata,json){const boundary='droid-archives-boundary';return{boundary,body:`--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${JSON.stringify(metadata)}\r\n--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n${JSON.stringify(json,null,2)}\r\n--${boundary}--`}}
async function readCloudDoc(fileId){const response=await driveFetch(`files/${fileId}?alt=media`);return normalizeCloudDoc(await response.json())}
